 1	import React from 'react';
 2	
 3	import { WizardTab } from '@catalog/wizard/tabs';
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 6	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 7	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 8	
 9	import WizardSchedulingGrid from './components/WizardSchedulingGrid';
10	
11	import './wizard-scheduling-tab.scss';
12	
13	const WizardSchedulingTab: WizardTab = ({ updateVM, vm }) => {
14	  return (
15	    <PageSection variant={PageSectionVariants.light}>
16	      <SidebarEditor<V1VirtualMachine>
17	        onResourceUpdate={updateVM}
18	        pathsToHighlight={PATHS_TO_HIGHLIGHT.SCHEDULING_TAB}
19	        resource={vm}
20	      >
21	        {(resource) => <WizardSchedulingGrid updateVM={updateVM} vm={resource} />}
22	      </SidebarEditor>
23	    </PageSection>
24	  );
25	};
26	
27	export default WizardSchedulingTab;

